#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
    float weight;
    int assign;
    float cost;
} Point;

inline float d_dist(int p1, int p2, int num, int dim, __global float *coord_d) {
    float retval = 0.0f;
    for (int i = 0; i < dim; i++) {
        float tmp = coord_d[(i * num) + p1] - coord_d[(i * num) + p2];
        retval += tmp * tmp;
    }
    return retval;
}

__kernel void kernel_compute_cost(
    const int num,
    const int dim,
    const long x,
    __global Point *p,
    const int K,
    const int stride,
    __global float *coord_d,
    __global float *work_mem_d,
    __global int *center_table_d,
    __global char *switch_membership_d)
{
    int gid = get_global_id(0);
    if (gid < num) {
        __global float *lower = &work_mem_d[gid * stride];

        float x_cost = d_dist(gid, (int)x, num, dim, coord_d) * p[gid].weight;

        if (x_cost < p[gid].cost) {
            switch_membership_d[gid] = 1;
            lower[K] += x_cost - p[gid].cost;
        } else {
            int assign_idx = p[gid].assign;
            if(assign_idx >= 0 && assign_idx < num) {
                int center_idx = center_table_d[assign_idx];
                lower[center_idx] += p[gid].cost - x_cost;
            }
        }
    }
}
